query:
-- How many SasBoss services exist?
SELECT COUNT(*) AS total_sasboss FROM services WHERE supplierName = 'SasBoss';

-- What service types do SasBoss services have?
SELECT serviceType, COUNT(*) AS cnt FROM services WHERE supplierName = 'SasBoss' GROUP BY serviceType ORDER BY cnt DESC;

-- Sample SasBoss services with their fields
SELECT externalId, serviceType, serviceTypeDetail, planName, supplierAccount, customerExternalId, monthlyCost, connectionId, locId, phoneNumber, locationAddress
FROM services WHERE supplierName = 'SasBoss' LIMIT 10;

